settings.css:
@font-face {
  font-family: 'IBM Plex Serif';
  font-style: normal;
  font-weight: 500;
  font-display: swap;
  src: url(https://fonts.gstatic.com/s/ibmplexserif/v20/jizAREVNn1dOx-zrZ2X3pZvkTi3s-CI0q1s.woff2) format('woff2');
  unicode-range: U+0000-00FF, U+0131, U+0152-0153, U+02BB-02BC, U+02C6, U+02DA, U+02DC, U+0304, U+0308, U+0329, U+2000-206F, U+20AC, U+2122, U+2191, U+2193, U+2212, U+2215, U+FEFF, U+FFFD;
}

.voice_container {
  margin: 0;
}

.voice_avatar {
  padding: 0;
  height: 100px;
  width: 150px;
  object-fit: cover;
  border-radius: 0;
  filter: brightness(50%);
  border: unset !important;
}

.wrapper_speaking .voice_avatar {
  filter: brightness(100%);
  border: unset !important;
}

li.voice_state {
  position: relative;
  display: inline-block;
  width: 150px;
  height: 100px;
}

.voice_states {
  display: flex;
  justify-content: right;
}

.voice_username > span {
  font-family: "IBM Plex Serif", normal !important;
  position: absolute;
  width: 100%;
  bottom: 0;
  left: 0;
  box-sizing: border-box;
  text-align: center;
  white-space: nowrap;
  text-overflow: clip;
  background-color: #191919;
  border-radius: 0;
}

.wrapper_speaking .voice_username > span {
  background-color: white !important;
  color: black !important;
}

body {
  background-color: rgba(0, 0, 0, 0);
  overflow: hidden;
  margin: 0;
  padding: 0;
}

li[data-userid="[enter Discord user ID here]"] {display: none; !important}

